const input = $input.first().json;
const {topic, project, avatar, pass_number, research_brief} = input;

// Per-pass cache short-circuit (migration 039 + WF_SCRIPT_GENERATE patch).
// If the caller has supplied a cached_result, it means this pass was already
// generated successfully in a prior run - return immediately so we save the
// 2-15 minute Claude Opus call and ~$0.30-0.40 in tokens. The cached object
// has the WF_SCRIPT_PASS return shape verbatim.
if (input.cached_result) {
  return [{json: {...input.cached_result, pass_number: pass_number, research_brief: research_brief || '', from_cache: true}}];
}

const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY, AK = $env.ANTHROPIC_API_KEY;
const PASS = pass_number || 1;
const WT = PASS === 2 ? '8,000-10,000 words' : '5,000-7,000 words';
const MIN_WORDS = PASS === 2 ? 8000 : 5000;
const MAX_WORDS = PASS === 2 ? 10000 : 7000;
const MAX = 3;

// PROGRESS-LOG: emit start event so the dashboard can render a live stepper.
// Fire-and-forget; errors here must never block script generation.
try {
  await fetch(SB + '/rest/v1/production_logs', {
    method: 'POST',
    headers: {
      apikey: SRK,
      Authorization: 'Bearer ' + SRK,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      topic_id: topic.id,
      stage: 'script_pass_' + PASS,
      action: 'started',
      status: 'in_progress',
      metadata: { pass: PASS, attempt: 0 }
    })
  });
} catch (_) { /* best-effort */ }


// CENTRAL INTELLIGENCE RENDERER (migration 028)
// Fetches stage-appropriate intelligence markdown from PL/pgSQL RPC.
// Replaces the old intelligence_block passthrough from WF_SCRIPT_GENERATE.
// Each pass fetches fresh - no threading bug between Pass 1/2/3.
const projectId = (topic && topic.project_id) || (project && project.id) || input.project_id;
let renderedIntelligence = '';
try {
  const intelRes = await fetch(SB + '/rest/v1/rpc/render_project_intelligence', {
    method: 'POST',
    headers: {
      apikey: $env.SUPABASE_ANON_KEY,
      Authorization: 'Bearer ' + SRK,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ p_project_id: projectId, p_stage: 'script' })
  });
  if (intelRes.ok) renderedIntelligence = await intelRes.json();
} catch (_) {}

async function gp(t) {
  const r = await fetch(SB + '/rest/v1/system_prompts?prompt_type=eq.' + t + '&is_active=eq.true&select=prompt_text', {headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK}});
  let pt = ((await r.json())?.[0]?.prompt_text) || '';
  // === BEGIN AU OVERLAY (migration 034) - substitute {country_*} placeholders if present
  const __PRE = /\{country_(?:compliance_block|terminology_block|calendar_context|demonetization_constraints)\}/;
  if (pt && __PRE.test(pt)) {
    try {
      const __ct = ((topic && topic.country_target) || (project && project.country_target) || 'GENERAL');
      const __cbRes = await fetch(SB + '/rest/v1/rpc/render_country_blocks', {
        method: 'POST',
        headers: { apikey: $env.SUPABASE_ANON_KEY, Authorization: 'Bearer ' + SRK, 'Content-Type': 'application/json' },
        body: JSON.stringify({ p_country_target: __ct })
      });
      if (__cbRes.ok) {
        const __cb = await __cbRes.json();
        pt = pt
          .replace(/\{country_compliance_block\}/g, (__cb.country_compliance_block || ''))
          .replace(/\{country_terminology_block\}/g, (__cb.country_terminology_block || ''))
          .replace(/\{country_calendar_context\}/g, (__cb.country_calendar_context || ''))
          .replace(/\{country_demonetization_constraints\}/g, (__cb.country_demonetization_constraints || ''));
      }
    } catch (_) { /* leave placeholders intact on RPC failure */ }
  }
  // === END AU OVERLAY ===
  return pt;
}

async function cc(s, u, m) {
  // 2026-05-07: Switched to STREAMING API. Earlier non-streaming + AbortController
  // patch was ineffective - Anthropic was dropping the long-poll connection at
  // ~5-6 min before the 12-min abort fired (3 retries � 6min = ~18min total
  // failure shape, identical to original 19min). Streaming keeps the connection
  // active via SSE events and is Anthropic's recommended path for long
  // completions. Per-attempt cap kept at 12 min via Promise.race against a
  // timeout (the SSE stream WILL die mid-token if we timeout - so re-attempt
  // from scratch is the only safe recovery).
  var maxRetries = 3;
  var perAttemptMs = 12 * 60 * 1000;
  var lastErr = null;
  for (var attempt = 1; attempt <= maxRetries; attempt++) {
    var ac = new AbortController();
    var timedOut = false;
    var timer = setTimeout(function() { timedOut = true; try { ac.abort(); } catch(_) {} }, perAttemptMs);
    try {
      var b = {
        model: 'claude-sonnet-4-20250514',
        max_tokens: m || 64000,
        messages: [{role: 'user', content: u}],
        stream: true
      };
      if (s) b.system = s;
      var r = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': AK,
          'anthropic-version': '2023-06-01'
        },
        body: JSON.stringify(b),
        signal: ac.signal
      });
      if (r.status === 429) {
        clearTimeout(timer);
        console.log('Rate limited (attempt ' + attempt + '/' + maxRetries + '), waiting 30s...');
        await new Promise(function(res) { setTimeout(res, 30000); });
        continue;
      }
      if (r.status === 529) {
        clearTimeout(timer);
        console.log('API overloaded (attempt ' + attempt + '/' + maxRetries + '), waiting 15s...');
        await new Promise(function(res) { setTimeout(res, 15000); });
        continue;
      }
      if (!r.ok) {
        clearTimeout(timer);
        var errBody = '';
        try { errBody = await r.text(); } catch(_) {}
        throw new Error('Claude HTTP ' + r.status + ': ' + errBody.slice(0, 300));
      }
      // === STREAMING SSE PARSER ===
      var reader = r.body.getReader();
      var decoder = new TextDecoder();
      var buf = '';
      var fullText = '';
      var apiError = null;
      while (true) {
        var chunk = await reader.read();
        if (chunk.done) break;
        buf += decoder.decode(chunk.value, {stream: true});
        var lines = buf.split('\n');
        buf = lines.pop() || '';
        for (var i = 0; i < lines.length; i++) {
          var line = lines[i].trim();
          if (!line || !line.indexOf('data: ') === 0 && line.indexOf('data:') !== 0) continue;
          var dataStr = line.indexOf('data: ') === 0 ? line.slice(6) : line.slice(5);
          dataStr = dataStr.trim();
          if (!dataStr || dataStr === '[DONE]') continue;
          try {
            var ev = JSON.parse(dataStr);
            if (ev.type === 'content_block_delta' && ev.delta && typeof ev.delta.text === 'string') {
              fullText += ev.delta.text;
            } else if (ev.type === 'error' && ev.error) {
              apiError = ev.error;
            }
          } catch (_) { /* skip malformed event */ }
        }
      }
      clearTimeout(timer);
      if (apiError) throw new Error('Claude stream error: ' + JSON.stringify(apiError));
      if (!fullText || fullText.length < 100) {
        throw new Error('Claude returned empty or near-empty stream (' + fullText.length + ' chars)');
      }
      return fullText;
    } catch (e) {
      clearTimeout(timer);
      lastErr = e;
      var msg = (e && e.message) ? e.message : String(e);
      var label = timedOut ? '12min timeout (abort fired)' : msg;
      console.log('cc() attempt ' + attempt + '/' + maxRetries + ' failed: ' + label);
      if (attempt < maxRetries) {
        var base = Math.min(5000 * Math.pow(2, attempt - 1), 30000);
        var jitter = Math.floor(Math.random() * 3000);
        var wait = base + jitter;
        console.log('Retrying in ' + Math.round(wait/1000) + 's...');
        await new Promise(function(res) { setTimeout(res, wait); });
      }
    }
  }
  throw lastErr || new Error('cc() failed after ' + maxRetries + ' attempts');
}

function fi(t, v) {
  let r = t;
  for (const [k, val] of Object.entries(v)) r = r.split('{' + k + '}').join(val || '');
  return r;
}

const [sysTpl, passTpl, evalTpl, retryTpl] = await Promise.all([
  gp('script_system_prompt'), gp('script_pass' + PASS), gp('script_evaluator'), gp('script_retry_template')
]);

const v = {
  subtopic: topic.seo_title || topic.original_title || '',
  niche_category: project.niche || '',
  target_audience_segment: topic.target_audience_segment || '',
  audience_avatar: avatar?.audience_avatar || avatar?.avatar_name_age || '',
  psychographics: topic.psychographics || '',
  key_emotional_drivers: topic.key_emotional_drivers || '',
  viewer_search_intent: topic.viewer_search_intent || '',
  core_domain_framework: topic.core_domain_framework || '',
  primary_problem_trigger: topic.primary_problem_trigger || '',
  content_angle_blue_ocean: topic.content_angle_blue_ocean || '',
  video_style_structure: topic.video_style_structure || '',
  practical_takeaways: topic.practical_takeaways || ''
};

if (PASS === 2) v.PASS_1_OUTPUT = input.pass1_output || '';

const sp = fi(sysTpl, v);
let origP = fi(passTpl, v);

if (PASS === 3) {
  origP = origP.replace(/\{PASS_1_SUMMARY[^}]*\}/g, input.pass1_summary || '');
  origP = origP.replace(/\{PASS_2_SUMMARY[^}]*\}/g, input.pass2_summary || '');
  origP = origP.replace(/\{CHARACTER_NAME\}/g, input.character_name || '');
  origP = origP.replace(/\{1-sentence[^}]*\}/g, input.character_status || '');
  origP = origP.replace(/\{LIST_OF_METAPHORS[^}]*\}/g, (input.metaphors_used || []).join(', '));
  origP = origP.replace(/\{LIST\s*\u2014[^}]*\}/g, (input.reassurance_phrases || []).join(', '));
  origP = origP.replace(/\{LIST_OF_NOTABLE_PHRASES[^}]*\}/g, (input.notable_phrases || []).join(', '));
}

